INSERT INTO `ec_reviews` VALUES (1,2,NULL,NULL,28,1.00,'Ok good product. I have some issues in customizations. But its not correct to blame the developer. The product is good. Good luck for your business.','published','2024-12-09 00:00:13','2024-12-09 00:00:13','[\"products\\/22-3.jpg\",\"products\\/46-1.jpg\"]'),(2,7,NULL,NULL,20,3.00,'Perfect +++++++++ i love it really also i get to fast ticket answers... Thanks Lot BOTBLE Teams','published','2024-12-09 00:00:13','2024-12-09 00:00:13','[\"products\\/45.jpg\",\"products\\/47-1.jpg\",\"products\\/59-3.jpg\"]'),(3,1,NULL,NULL,57,5.00,'Customer Support are grade (A*), however the code is a way too over engineered for it\'s purpose.','published','2024-12-09 00:00:13','2024-12-09 00:00:13','[\"products\\/33-2.jpg\",\"products\\/47-1.jpg\"]'),(4,1,NULL,NULL,33,5.00,'Perfect +++++++++ i love it really also i get to fast ticket answers... Thanks Lot BOTBLE Teams','published','2024-12-09 00:00:13','2024-12-09 00:00:13','[\"products\\/35.jpg\",\"products\\/49-2.jpg\"]'),(5,3,NULL,NULL,23,1.00,'The script is the best of its class, fast, easy to implement and work with , and the most important thing is the great support team , Recommend with no doubt.','published','2024-12-09 00:00:13','2024-12-09 00:00:13','[\"products\\/5-3.jpg\",\"products\\/13.jpg\",\"products\\/31-1.jpg\",\"products\\/39-1.jpg\"]'),(6,5,NULL,NULL,5,3.00,'Those guys now what they are doing, the release such a good product that it\'s a pleasure to work with ! Even when I was stuck on the project, I created a ticket and the next day it was replied by the team. GOOD JOB guys. I love working with them :)','published','2024-12-09 00:00:13','2024-12-09 00:00:13','[\"products\\/34.jpg\",\"products\\/41-2.jpg\"]'),(7,6,NULL,NULL,40,1.00,'Amazing code, amazing support. Overall, im really confident in Botble and im happy I made the right choice! Thank you so much guys for coding this masterpiece','published','2024-12-09 00:00:13','2024-12-09 00:00:13','[\"products\\